INSERT INTO `paragrafo` (`id`, `ordem`, `texto`, `imagemFile_id`, `questao_id`) VALUES (86366,1,'Por exemplo, se o contribuinte tem menos de cinquenta anos e renda anual de R$ 40.000,00, ele paga 0,2∙20.000 + 0,3∙10.000 = 7.000 reais de imposto de renda; mas, se o contribuinte tem cinquenta anos ou mais, ele paga de impostos 0,2∙25.000 + 0,3∙0 = 5.000 reais. Considerando esses dados, responda à seguinte questão: se um contribuinte, com renda anual superior a R$ 45.000,00, atinge a idade de cinquenta anos ou mais, mantendo a mesma renda anual, de quanto diminui o seu imposto, em relação ao de quando tinha menos de cinquenta anos?',NULL,86364);
